import { createAsyncThunk } from '@reduxjs/toolkit';
import { authorizedAxiosInstance } from '~/utils/axios';

export const updateCardDetails = createAsyncThunk(
  'cards/updateDetails',
  async ({ cardId, data }, { rejectWithValue }) => {
    try {
      const response = await authorizedAxiosInstance.put(`/v1/cards/${cardId}`, data);
      return response.data; // Trả về card đã được cập nhật từ API
    } catch (error) {
      return rejectWithValue(error.response.data);
    }
  }
);

